    const std::vector<std::vector<int>>& B) {

    int m = A.size();
    int n = B[0].size();

    int p = B.size();

    std::vector<std::vector<int>> C(m, std::vector<int>(n, 0));

    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            for (int k = 0; k < p; k++) {
                C[i][j] ^= (A[i][k] & B[k][j]);
            }
        }
    }

    return C;
}

